import{_ as n,C as a,o as h,c as s,ae as l,E as r,j as d,a as i}from"./chunks/framework.DNDrU9L4.js";const _=JSON.parse('{"title":"かわいいだけじゃだめですか？ — 가사로 배우기","description":"","frontmatter":{},"headers":[],"relativePath":"japanese/lyrics/kawaii-dake.md","filePath":"japanese/lyrics/kawaii-dake.md"}'),b={name:"japanese/lyrics/kawaii-dake.md"};function c(p,t,u,k,q,f){const e=a("Flashcard"),o=a("Quiz");return h(),s("div",null,[t[0]||(t[0]=l(`<h1 id="かわいいだけじゃだめですか-—-가사로-배우기" tabindex="-1">かわいいだけじゃだめですか？ — 가사로 배우기 <a class="header-anchor" href="#かわいいだけじゃだめですか-—-가사로-배우기" aria-label="Permalink to &quot;かわいいだけじゃだめですか？ — 가사로 배우기&quot;">​</a></h1><h2 id="곡-소개" tabindex="-1">곡 소개 <a class="header-anchor" href="#곡-소개" aria-label="Permalink to &quot;곡 소개&quot;">​</a></h2><p>2024년 9월 데뷔 싱글. 작사작곡: 早川裕高 / 渡辺俊彦. 큐티스트리트의 시그니처 곡으로, &quot;귀엽기만 하면 안 되나요?&quot;라는 자신감 넘치는 메시지를 담았습니다. 아침에 서둘러 준비하고, 거울 앞에서 메이크업을 하며 자신만의 귀여움에 자신감을 갖는 소녀의 이야기를 그린 업비트 팝송입니다.</p><hr><h2 id="타이틀-분석" tabindex="-1">타이틀 분석 <a class="header-anchor" href="#타이틀-분석" aria-label="Permalink to &quot;타이틀 분석&quot;">​</a></h2><table tabindex="0"><thead><tr><th>단어</th><th>읽기</th><th>뜻</th></tr></thead><tbody><tr><td>かわいい</td><td>카와이이</td><td>귀여운</td></tr><tr><td>だけ</td><td>다케</td><td>~만, ~뿐</td></tr><tr><td>じゃ</td><td>쟈</td><td>~에서는 (では의 구어체)</td></tr><tr><td>だめ</td><td>다메</td><td>안 돼, 소용없어</td></tr><tr><td>ですか</td><td>데스카</td><td>~인가요? (정중한 의문)</td></tr></tbody></table><p><strong>전체 해석</strong>: &quot;귀엽기만 하면 안 되나요?&quot;</p><blockquote><p><strong>포인트</strong>: じゃ는 では의 구어체 줄임말입니다. 문어체로 쓰면 「かわいいだけではだめですか？」가 됩니다.</p></blockquote><hr><h2 id="곡에서-배우는-단어" tabindex="-1">곡에서 배우는 단어 <a class="header-anchor" href="#곡에서-배우는-단어" aria-label="Permalink to &quot;곡에서 배우는 단어&quot;">​</a></h2><table tabindex="0"><thead><tr><th>일본어</th><th>읽기</th><th>뜻</th><th>예문</th></tr></thead><tbody><tr><td>大変</td><td>타이헨</td><td>큰일, 힘들다</td><td>大変だ！遅刻する！ (큰일이다! 지각하겠어!)</td></tr><tr><td>出かける</td><td>데카케루</td><td>외출하다</td><td>もう出かける時間だよ。(벌써 나갈 시간이야.)</td></tr><tr><td>遅刻</td><td>치코쿠</td><td>지각</td><td>遅刻しちゃう！(지각하겠어!)</td></tr><tr><td>鏡</td><td>카가미</td><td>거울</td><td>鏡を見て準備する。(거울을 보며 준비한다.)</td></tr><tr><td>準備</td><td>쥰비</td><td>준비</td><td>準備できた！(준비 완료!)</td></tr><tr><td>メイク</td><td>메이쿠</td><td>메이크업</td><td>メイクが楽しい！(메이크업이 즐거워!)</td></tr><tr><td>可愛い</td><td>카와이이</td><td>귀여운</td><td>今日も可愛い！(오늘도 귀여워!)</td></tr><tr><td>最強</td><td>사이쿄</td><td>최강</td><td>可愛さ最強！(귀여움 최강!)</td></tr><tr><td>自信</td><td>지신</td><td>자신감</td><td>自信を持って！(자신감을 가져!)</td></tr><tr><td>キラキラ</td><td>키라키라</td><td>반짝반짝</td><td>目がキラキラしてる。(눈이 반짝반짝해.)</td></tr><tr><td>笑顔</td><td>에가오</td><td>미소, 웃는 얼굴</td><td>笑顔が一番！(미소가 최고!)</td></tr><tr><td>世界</td><td>세카이</td><td>세계</td><td>世界中に笑顔を届けたい。(세계에 미소를 전하고 싶어.)</td></tr><tr><td>輝く</td><td>카가야쿠</td><td>빛나다</td><td>舞台で輝く！(무대에서 빛난다!)</td></tr><tr><td>ハート</td><td>하토</td><td>하트</td><td>ハートを届けよう。(하트를 전하자.)</td></tr><tr><td>夢</td><td>유메</td><td>꿈</td><td>夢をあきらめない。(꿈을 포기하지 않는다.)</td></tr><tr><td>ステージ</td><td>스테지</td><td>스테이지, 무대</td><td>ステージに立つ。(무대에 선다.)</td></tr><tr><td>全力</td><td>젠료쿠</td><td>전력, 최선</td><td>全力で頑張る！(전력으로 열심히 한다!)</td></tr><tr><td>気持ち</td><td>키모치</td><td>기분, 마음</td><td>気持ちを伝えたい。(마음을 전하고 싶다.)</td></tr></tbody></table><hr><h2 id="핵심-문법-3가지" tabindex="-1">핵심 문법 3가지 <a class="header-anchor" href="#핵심-문법-3가지" aria-label="Permalink to &quot;핵심 문법 3가지&quot;">​</a></h2><h3 id="_1-だけじゃだめですか-만으로는-안-되나요" tabindex="-1">1. ～だけじゃだめですか (～만으로는 안 되나요?) <a class="header-anchor" href="#_1-だけじゃだめですか-만으로는-안-되나요" aria-label="Permalink to &quot;1. ～だけじゃだめですか (～만으로는 안 되나요?)&quot;">​</a></h3><p>이 곡의 핵심 표현입니다. 구조를 분해해서 봅시다.</p><table tabindex="0"><thead><tr><th>구성요소</th><th>역할</th><th>예시</th></tr></thead><tbody><tr><td>だけ</td><td>~만, ~뿐 (한정)</td><td>可愛いだけ = 귀엽기만</td></tr><tr><td>じゃ (=では)</td><td>~에서는, ~으로는 (조건)</td><td>可愛いだけじゃ = 귀엽기만으로는</td></tr><tr><td>だめ</td><td>안 돼, 불충분</td><td>だめですか = 안 되나요?</td></tr></tbody></table><p><strong>응용 연습</strong>:</p><table tabindex="0"><thead><tr><th>일본어</th><th>뜻</th></tr></thead><tbody><tr><td>好きなだけじゃだめですか？</td><td>좋아하기만 하면 안 되나요?</td></tr><tr><td>歌うだけじゃだめですか？</td><td>노래하기만 하면 안 되나요?</td></tr><tr><td>笑顔だけじゃだめですか？</td><td>미소만으로는 안 되나요?</td></tr></tbody></table><hr><h3 id="_2-なきゃ-해야-해-—-구어체-축약형" tabindex="-1">2. ～なきゃ (～해야 해) — 구어체 축약형 <a class="header-anchor" href="#_2-なきゃ-해야-해-—-구어체-축약형" aria-label="Permalink to &quot;2. ～なきゃ (～해야 해) — 구어체 축약형&quot;">​</a></h3><p>일상 대화에서 자주 쓰는 구어체 표현입니다. 아침에 서두르는 장면에서 자주 등장합니다.</p><table tabindex="0"><thead><tr><th>문어체 (정식)</th><th>구어체 (축약)</th><th>뜻</th></tr></thead><tbody><tr><td>しなければならない</td><td>しなきゃ</td><td>해야 해</td></tr><tr><td>行かなければ</td><td>行かなきゃ</td><td>가야 해</td></tr><tr><td>準備しなければ</td><td>準備しなきゃ</td><td>준비해야 해</td></tr><tr><td>起きなければ</td><td>起きなきゃ</td><td>일어나야 해</td></tr></tbody></table><blockquote><p><strong>포인트</strong>: なければ → なきゃ로 줄어드는 것이 포인트! 급할 때, 혼잣말할 때 주로 사용합니다.</p></blockquote><hr><h3 id="_3-くなる-형용사-なる-해지다" tabindex="-1">3. ～くなる (형용사 + なる = ~해지다) <a class="header-anchor" href="#_3-くなる-형용사-なる-해지다" aria-label="Permalink to &quot;3. ～くなる (형용사 + なる = ~해지다)&quot;">​</a></h3><p>상태의 변화를 표현하는 패턴입니다. い형용사의 어미 い를 く로 바꾸고 なる를 붙입니다.</p><table tabindex="0"><thead><tr><th>형용사</th><th>～くなる</th><th>뜻</th></tr></thead><tbody><tr><td>かわいい</td><td>かわいくなる</td><td>귀여워지다</td></tr><tr><td>強い (강하다)</td><td>強くなる</td><td>강해지다</td></tr><tr><td>明るい (밝다)</td><td>明るくなる</td><td>밝아지다</td></tr><tr><td>自信がある</td><td>自信が出てくる</td><td>자신감이 생기다</td></tr></tbody></table><blockquote><p><strong>포인트</strong>: な형용사는 に + なる를 씁니다. 例: 素敵になる (멋있어지다), 元気になる (건강해지다).</p></blockquote><hr><h2 id="문화-노트" tabindex="-1">문화 노트 <a class="header-anchor" href="#문화-노트" aria-label="Permalink to &quot;문화 노트&quot;">​</a></h2><h3 id="일본의-「カワイイ」-문화" tabindex="-1">일본의 「カワイイ」 문화 <a class="header-anchor" href="#일본의-「カワイイ」-문화" aria-label="Permalink to &quot;일본의 「カワイイ」 문화&quot;">​</a></h3><p>일본에서 「可愛い」(카와이이)는 단순히 &quot;귀여운&quot;을 넘어 하나의 문화가 되었습니다.</p><ul><li><strong>하라주쿠(原宿)</strong>: 도쿄의 카와이이 패션 성지. 독특하고 화려한 스타일이 발신되는 곳</li><li><strong>アイドル文化</strong>: 일본 아이돌에게 &quot;귀여움&quot;은 능력이자 무기. 노래, 댄스, 개성과 함께 카와이이함이 중요한 요소</li><li><strong>메이크업과 패션</strong>: 아이돌의 메이크업 영상, 패션 스타일은 팬들에게 큰 영향을 미침</li></ul><h3 id="일본-여고생의-아침-루틴-노래-배경" tabindex="-1">일본 여고생의 아침 루틴 (노래 배경) <a class="header-anchor" href="#일본-여고생의-아침-루틴-노래-배경" aria-label="Permalink to &quot;일본 여고생의 아침 루틴 (노래 배경)&quot;">​</a></h3><p>이 곡에 묘사된 아침 장면은 일본 학생들의 전형적인 아침을 담고 있습니다.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>起きる (일어나다) → 準備する (준비하다) → 鏡を見る (거울 보다)</span></span>
<span class="line"><span>→ メイクする (메이크업하다) → 遅刻しそう！(지각할 것 같아!)</span></span>
<span class="line"><span>→ 全力で走る (전력 질주) → でも可愛いから大丈夫 (하지만 귀여우니까 괜찮아)</span></span></code></pre></div><hr><h2 id="단어-플래시카드" tabindex="-1">단어 플래시카드 <a class="header-anchor" href="#단어-플래시카드" aria-label="Permalink to &quot;단어 플래시카드&quot;">​</a></h2><p>클릭해서 뒤집어 보세요!</p>`,39)),r(e,{cards:[{front:"大変 (たいへん)",back:"큰일, 힘들다"},{front:"出かける (でかける)",back:"외출하다"},{front:"遅刻 (ちこく)",back:"지각"},{front:"鏡 (かがみ)",back:"거울"},{front:"準備 (じゅんび)",back:"준비"},{front:"メイク",back:"메이크업"},{front:"最強 (さいきょう)",back:"최강"},{front:"自信 (じしん)",back:"자신감"},{front:"キラキラ",back:"반짝반짝"},{front:"笑顔 (えがお)",back:"미소, 웃는 얼굴"},{front:"輝く (かがやく)",back:"빛나다"},{front:"全力 (ぜんりょく)",back:"전력, 최선"},{front:"気持ち (きもち)",back:"기분, 마음"},{front:"ステージ",back:"스테이지, 무대"},{front:"夢 (ゆめ)",back:"꿈"}]}),t[1]||(t[1]=d("hr",null,null,-1)),t[2]||(t[2]=d("h2",{id:"가사-퀴즈",tabindex:"-1"},[i("가사 퀴즈 "),d("a",{class:"header-anchor",href:"#가사-퀴즈","aria-label":'Permalink to "가사 퀴즈"'},"​")],-1)),t[3]||(t[3]=d("p",null,"8문제에 도전! 어휘와 문법을 함께 확인해 봅시다.",-1)),r(o,{questions:[{q:"「かわいい」의 뜻은?",options:["멋진","귀여운","강한","즐거운"],answer:1},{q:"「だけ」의 역할은?",options:["~도","~만/~뿐","~부터","~까지"],answer:1},{q:"「遅刻」(ちこく)의 뜻은?",options:["조퇴","결석","지각","외출"],answer:2},{q:"「準備」(じゅんび)의 뜻은?",options:["정리","준비","청소","운동"],answer:1},{q:"「行かなきゃ」를 정중한 형태로 바꾸면?",options:["行かなければならない","行きたい","行ってもいい","行かないでほしい"],answer:0},{q:"「かわいくなる」의 뜻은?",options:["귀여워 보이다","귀여워지다","귀엽게 하다","귀여움을 전하다"],answer:1},{q:"「全力」(ぜんりょく)의 뜻은?",options:["반력","전기","전력/최선","체력"],answer:2},{q:"「じゃ」는 어떤 단어의 구어체?",options:["では","でも","だから","だが"],answer:0}]})])}const x=n(b,[["render",c]]);export{_ as __pageData,x as default};
